void user_init() {
  // The in-house libstdc++ lazily registers its locale-facet cleanup nodes
  // (_Fac_node list) the first time a facet is used, allocating them with the
  // global operator new / new[]. In this program those operators are routed
  // through g_custom_heap once it is installed. The facet cleanup runs at
  // program exit (~_Fac_tidy_reg_t), long after g_custom_heap has been torn
  // down, so freeing arena-interior pointers crashes under RELEASE.
  //
  // user_init() runs before g_custom_heap is installed, so forcing the facet
  // registration here makes those nodes allocate via plain malloc and be freed
  // correctly at exit. A single numeric formatting op exercises num_put /
  // numpunct through use_facet, which triggers the registration.
  std::ostringstream oss;
  oss.imbue(std::locale::classic());
  oss << 0 << 0.0;
  (void)oss.str();
}
